def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for j in range(1, 21):
                if j % 2 == 0:
                    term = ((-1) ** (j//2)) * (ratio ** j) / j
                else:
                    term = ((-1) ** ((j+1)//2)) * (ratio ** j) / (j*j)
                score += term
            multiplier = 1
            for k in range(1, 6):
                if capacity < item * (1 + k*0.1):
                    multiplier += 0.1 * k
                else:
                    multiplier -= 0.05 * k
            if multiplier < 0.5:
                multiplier = 0.5
            if capacity < item * 1.5:
                multiplier *= 1.3
            adjusted_score = -score * multiplier
            if adjusted_score < 0:
                adjusted_score = 0
            priorities[i] = adjusted_score
    return priorities
